#!/usr/bin/env node
/**
 * compare-bundle-size.js
 *
 * Compares webpack bundle sizes between the PR branch and the base branch.
 * Usage:
 *   node scripts/compare-bundle-size.js \
 *     --base-sizes  base-sizes.json  \
 *     --pr-sizes    pr-sizes.json    \
 *     --threshold   5                \
 *     [--output     report.md]
 *
 * sizes JSON format (generated by measure-bundle-size.js):
 *   { "main": 14000000, "renderer": 31000000, "total": 45000000 }
 */

'use strict';

const fs   = require('fs');
const path = require('path');

// ─── CLI argument parsing ───────────────────────────────────────────────────
const args = process.argv.slice(2);
function getArg(name) {
  const idx = args.indexOf(name);
  return idx !== -1 ? args[idx + 1] : null;
}

const baseFile  = getArg('--base-sizes');
const prFile    = getArg('--pr-sizes');
const threshold = parseFloat(getArg('--threshold') || '5');
const outputMd  = getArg('--output');

if (!baseFile || !prFile) {
  console.error('Usage: node compare-bundle-size.js --base-sizes <file> --pr-sizes <file> [--threshold 5] [--output report.md]');
  process.exit(1);
}

// ─── Load data ──────────────────────────────────────────────────────────────
const base = JSON.parse(fs.readFileSync(baseFile, 'utf8'));
const pr   = JSON.parse(fs.readFileSync(prFile,   'utf8'));

// ─── Calculate diff ─────────────────────────────────────────────────────────
function fmt(bytes) {
  if (bytes >= 1024 * 1024) return (bytes / (1024 * 1024)).toFixed(2) + ' MB';
  if (bytes >= 1024)        return (bytes / 1024).toFixed(2) + ' KB';
  return bytes + ' B';
}

function pct(before, after) {
  if (before === 0) return 'N/A';
  const delta = ((after - before) / before) * 100;
  return (delta >= 0 ? '+' : '') + delta.toFixed(2) + '%';
}

function icon(before, after, thresh) {
  if (before === 0) return '➕';
  const delta = ((after - before) / before) * 100;
  if (delta >= thresh)  return '🔴'; // failed
  if (delta >= thresh * 0.6) return '🟡'; // warning (>60% of threshold)
  if (delta > 0) return '🟢';            // slight increase, still ok
  return '✅';                            // decreased or same
}

const buckets = Object.keys({ ...base, ...pr }).filter(k => k !== 'total');
const rows = buckets.map(bucket => {
  const b = base[bucket] || 0;
  const p = pr[bucket]   || 0;
  const delta = p - b;
  return { bucket, b, p, delta };
});

const totalBase  = base.total || buckets.reduce((s, k) => s + (base[k] || 0), 0);
const totalPr    = pr.total   || buckets.reduce((s, k) => s + (pr[k]   || 0), 0);
const totalDelta = totalPr - totalBase;
const totalPctVal = totalBase === 0 ? 0 : (totalDelta / totalBase) * 100;
const failed     = totalPctVal >= threshold;

// ─── Generate Markdown report ─────────────────────────────────────────────
const status = failed
  ? `## ❌ Bundle Size Check FAILED — increase ≥ ${threshold}%`
  : `## ✅ Bundle Size Check PASSED`;

const lines = [
  status,
  '',
  `> Threshold: **${threshold}%** | Total change: **${pct(totalBase, totalPr)}** (${fmt(totalBase)} → ${fmt(totalPr)}, ${totalDelta >= 0 ? '+' : ''}${fmt(Math.abs(totalDelta))})`,
  '',
  '| Bundle | Base | PR | Delta | % | Status |',
  '|--------|------|----|-------|---|--------|',
  ...rows.map(r =>
    `| \`${r.bucket}\` | ${fmt(r.b)} | ${fmt(r.p)} | ${r.delta >= 0 ? '+' : ''}${fmt(Math.abs(r.delta))} | ${pct(r.b, r.p)} | ${icon(r.b, r.p, threshold)} |`
  ),
  `| **Total** | **${fmt(totalBase)}** | **${fmt(totalPr)}** | **${totalDelta >= 0 ? '+' : ''}${fmt(Math.abs(totalDelta))}** | **${pct(totalBase, totalPr)}** | ${icon(totalBase, totalPr, threshold)} |`,
  '',
  '<details>',
  '<summary>Legend</summary>',
  '',
  '- ✅ Size decreased or unchanged',
  '- 🟢 Slight increase (< 60% of threshold)',
  `- 🟡 Warning (≥ ${(threshold * 0.6).toFixed(1)}% increase)`,
  `- 🔴 FAILED (≥ ${threshold}% increase)`,
  '',
  '_Note: These sizes reflect the webpack-compiled JS bundles (`dist/main` + `dist/renderer`). Native modules and the Electron binary are not included as they are not affected by code changes._',
  '</details>',
].join('\n');

// ─── Output ─────────────────────────────────────────────────────────────────
console.log(lines);
if (outputMd) {
  fs.writeFileSync(outputMd, lines, 'utf8');
  console.error(`\nReport written to: ${outputMd}`);
}

// ─── Exit code ──────────────────────────────────────────────────────────────
if (failed) {
  console.error(`\n[FAIL] Total bundle size increased by ${totalPctVal.toFixed(2)}% which is >= threshold ${threshold}%`);
  process.exit(1);
} else {
  console.error(`\n[PASS] Total bundle size change: ${totalPctVal.toFixed(2)}% (threshold: ${threshold}%)`);
  process.exit(0);
}
